// Pull both ensures conjuncts into the proof context so the deeply nested
// `self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va)`
// and `...mapping_4k()[va]` terms get instantiated identically for r1 and r2.
assert(self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va)
    == r1.is_Some());
assert(self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va)
    == r2.is_Some());
assert(r1.is_Some() ==>
    self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va)
    && self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()[va]
        == page_entry_to_map_entry(&r1.unwrap()));
assert(r2.is_Some() ==>
    self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va)
    && self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()[va]
        == page_entry_to_map_entry(&r2.unwrap()));

// Both is_Some flags are determined by the same dom().contains(va) value,
// so they agree.
assert(r1.is_Some() == r2.is_Some());
assert(r1.is_None() == r2.is_None());

// In the Some-case, both unwrapped page entries are forced (transitively
// through `mapping_4k()[va]`) to project to the same MapEntry.
if r1.is_Some() {
    assert(r2.is_Some());
    assert(self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va));
    assert(page_entry_to_map_entry(&r1.unwrap())
        == self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()[va]);
    assert(page_entry_to_map_entry(&r2.unwrap())
        == self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()[va]);
    assert(page_entry_to_map_entry(&r1.unwrap())
        == page_entry_to_map_entry(&r2.unwrap()));
}
